starterCss:
/* Fix accessibility issues:
   1. Inputs have outline: none (removes focus indicator)
   2. Note text has poor contrast (light gray on white)
   3. No prefers-reduced-motion handling for the button animation
   4. Focus states should use :focus-visible, not :focus */
.a11y-form {
  max-width: 400px;
  padding: 24px;
}
.field {
  margin-bottom: 16px;
}
.field label {
  display: block;
  margin-bottom: 4px;
  font-weight: bold;
}
.a11y-input {
  width: 100%;
  padding: 8px 12px;
  border: 2px solid #ccc;
  border-radius: 4px;
  font-size: 16px;
  outline: none; /* BAD: removes focus indicator */
  box-sizing: border-box;
}
.a11y-btn {
  padding: 10px 24px;
  background-color: #007bff;
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 16px;
  animation: pulse-btn 2s infinite; /* No reduced-motion check */
}
@keyframes pulse-btn {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.05); }
}
.a11y-note {
  color: #ddd; /* BAD: fails WCAG contrast on white bg */
  font-size: 12px;
}

