.a11y-form {
  max-width: 400px;
  padding: 24px;
}
.field {
  margin-bottom: 16px;
}
.field label {
  display: block;
  margin-bottom: 4px;
  font-weight: bold;
}
.a11y-input {
  width: 100%;
  padding: 8px 12px;
  border: 2px solid #ccc;
  border-radius: 4px;
  font-size: 16px;
  box-sizing: border-box;
}
.a11y-input:focus-visible {
  outline: 3px solid rgb(0, 123, 255);
  outline-offset: 2px;
  border-color: rgb(0, 123, 255);
}
.a11y-btn {
  padding: 10px 24px;
  background-color: rgb(0, 123, 255);
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 16px;
  animation: pulse-btn 2s infinite;
}
.a11y-btn:focus-visible {
  outline: 3px solid rgb(0, 123, 255);
  outline-offset: 2px;
}
@keyframes pulse-btn {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.05); }
}
@media (prefers-reduced-motion: reduce) {
  .a11y-btn {
    animation: none;
  }
}
.a11y-note {
  color: rgb(108, 117, 125);
  font-size: 12px;
}

